import{_ as e,o as t,c as r,a5 as l}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"学习记录 #0006：ADC采样技术——从传感器到数字量","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0006：ADC采样技术——从传感器到数字量","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第6课 — ADC采样技术 **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0006-adc-sampling-techniques.md","filePath":"content/power/archive/old-learning-records/0006-adc-sampling-techniques.md","lastUpdated":null}'),i={name:"content/power/archive/old-learning-records/0006-adc-sampling-techniques.md"};function o(n,a,s,c,d,h){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="学习记录-0006-adc采样技术——从传感器到数字量" tabindex="-1">学习记录 #0006：ADC采样技术——从传感器到数字量 <a class="header-anchor" href="#学习记录-0006-adc采样技术——从传感器到数字量" aria-label="Permalink to &quot;学习记录 #0006：ADC采样技术——从传感器到数字量&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第6课 — ADC采样技术 <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>采样信号全景</strong>：电流（最高优先级）→ 母线电压 → 输出电压 → 电池 → 温度（最低）</li><li><strong>电流采样选型</strong>：&lt;50A用分流电阻（精度高成本低），&gt;50A用霍尔传感器（隔离无损耗）</li><li><strong>低侧电阻采样</strong>：10mΩ合金电阻 + 16.5倍差分运放 + RC滤波，Kelvin四端接法</li><li><strong>PWM-ADC同步</strong>：中心对齐PEAK点触发ADC，下管导通中点采样，延迟0.5Tsw</li><li><strong>三相必须同步</strong>：不同步→Clarke/Park后2倍频纹波→控制振荡</li><li><strong>零偏校准</strong>：PWM未输出时采样256次取平均，运行时减去零偏</li><li><strong>过采样</strong>：4×→+1位，16×→+2位，只适用于慢变信号，不适用于电流环</li></ol><h2 id="代码要点" tabindex="-1">代码要点 <a class="header-anchor" href="#代码要点" aria-label="Permalink to &quot;代码要点&quot;">​</a></h2><ul><li>零偏校准：PWM关断时256次平均，运行时减偏移</li><li>C2000配置：ePWM SOCA触发 → ADCA SOC0/1/2 → DMA搬运 → ISR执行PI</li><li>过采样：N次采样求和右移log2(N)/2位</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 单电阻采样重构三相电流的具体算法？</li><li>[ ] 隔离运放AMC1301的电路设计？</li><li>[ ] 高侧电流采样的共模电压抑制方法？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第7课：单相PFC整流器（Phase 2核心拓扑开始）</p>',10)])])}const p=e(i,[["render",o]]);export{u as __pageData,p as default};
